package com.cognizant.billing.model;import jakarta.persistence.*;@Entity public class Bill {@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;private Long customerId;private Double amount;private String status; public Long getId(){return id;} public void setId(Long id){this.id=id;} public Long getCustomerid(){return customerId;} public void setCustomerid(Long customerId){this.customerId=customerId;}public Double getAmount(){return amount;} public void setAmount(Double amount){this.amount=amount;}public String getStatus(){return status;} public void setStatus(String status){this.status=status;}}